export const 鎮宅官司 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿二＋人字圈鏈
    線(p => p.M(X(1.0), Z(1.5)).L(X(6.6), Z(1.4)));
    圈(0.7, 1.5);
    圈(6.9, 1.4);
    線(p => p.M(X(1.0), Z(2.6)).L(X(6.6), Z(2.5)));
    圈(0.7, 2.6);
    圈(6.9, 2.5);
    圈(3.4, 3.3);
    連([3.4, 3.3], [1.3, 4.0]);
    連([3.4, 3.3], [5.3, 4.0]);
    圈(1.3, 4.0);
    圈(5.3, 4.0);
    // 日日箱對
    const 日 = (x0) => {
        線(p => p.M(X(x0), Z(4.6)).L(X(x0), Z(6.4)).L(X(x0 + 2.2), Z(6.35))
            .L(X(x0 + 2.2), Z(4.55)).L(X(x0 - 0.05), Z(4.6)));
        線(p => p.M(X(x0 + 0.1), Z(5.5)).L(X(x0 + 2.1), Z(5.47)), 0.32);
    };
    日(1.0);
    日(4.0);
    // 雙目梯（上下各二箱）夾弜弓曲中層
    const 梯 = (x0, x1, z0, 層) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z0 + 層 * 1.6)));
        線(p => p.M(X(x1), Z(z0 - 0.05)).L(X(x1), Z(z0 + 層 * 1.6 - 0.05)));
        for (let i = 0; i <= 層; i++)
            線(p => p.M(X(x0), Z(z0 + i * 1.6)).L(X(x1), Z(z0 + i * 1.6 - 0.05)));
    };
    梯(0.9, 3.3, 7.2, 2);
    梯(4.3, 6.8, 7.2, 2);
    // 弜弓曲中層
    const 弓 = (cx) => 線(p => p.M(X(cx), Z(10.9))
        .C(X(cx - 0.6), Z(11.4), X(cx - 0.5), Z(12.0), X(cx + 0.1), Z(12.2))
        .C(X(cx + 0.6), Z(12.4), X(cx + 0.7), Z(12.9), X(cx + 0.2), Z(13.2)), 0.36);
    弓(1.6);
    弓(2.8);
    弓(4.9);
    弓(6.1);
    梯(0.9, 3.3, 13.8, 2);
    梯(4.3, 6.8, 13.8, 2);
    // 底桁
    線(p => p.M(X(1.0), Z(17.6)).L(X(6.7), Z(17.5)), 0.42);
    線(p => p.M(X(1.0), Z(18.5)).L(X(6.7), Z(18.4)), 0.42);
};
